import { Component, Input, ViewChild, ElementRef, AfterViewInit, OnDestroy } from '@angular/core';
import { NgModule } from '@angular/core';
import { BrowserModule } from '@angular/platform-browser';

@Component({
  selector: 'app-lazy-image',
  template: `
    <div
      #frame
      [style.width.px]="width"
      [style.height.px]="height"
      style="position: relative; border-radius: 8px; overflow: hidden; background: #e2e8f0;"
    >
      <div *ngIf="!loaded" style="position: absolute; inset: 0; display: flex; align-items: center; justify-content: center; color: #94a3b8; font-size: 13px;">
        {{ visible ? 'Loading…' : 'Scroll to load' }}
      </div>
      <img
        *ngIf="visible"
        [src]="src"
        [alt]="alt"
        (load)="loaded = true"
        [style.opacity]="loaded ? 1 : 0"
        style="width: 100%; height: 100%; display: block; object-fit: cover; transition: opacity 0.4s ease;"
      />
    </div>
  `,
})
export class LazyImageComponent implements AfterViewInit, OnDestroy {
  @Input() src = '';
  @Input() width = 300;
  @Input() height = 160;
  @Input() alt = '';
  visible = false;
  loaded = false;
  private io: IntersectionObserver | null = null;

  @ViewChild('frame') frame!: ElementRef<HTMLElement>;

  ngAfterViewInit(): void {
    this.io = new IntersectionObserver(
      ([entry]) => {
        if (entry.isIntersecting && this.io) {
          this.visible = true;
          this.io.disconnect();
        }
      },
      { rootMargin: '100px' }
    );
    this.io.observe(this.frame.nativeElement);
  }

  ngOnDestroy(): void {
    if (this.io) {
      this.io.disconnect();
    }
  }
}

@Component({
  selector: 'app-root',
  template: `
    <div style="font-family: sans-serif; padding: 20px;">
      <h1>Lazy Image Demo</h1>
      <p style="color: #666;">Scroll down — each image loads as it nears the viewport.</p>
      <div *ngFor="let h of hues" style="margin-bottom: 40px;">
        <app-lazy-image [src]="img(h)" [width]="300" [height]="160" [alt]="'Image ' + h"></app-lazy-image>
      </div>
    </div>
  `,
})
export class AppComponent {
  hues = [10, 90, 170, 250, 330];

  img(hue: number): string {
    return (
      'data:image/svg+xml;utf8,' +
      encodeURIComponent(
        "<svg xmlns='http://www.w3.org/2000/svg' width='300' height='160'><rect width='100%' height='100%' fill='hsl(" +
          hue +
          ",70%,55%)'/><text x='50%' y='50%' fill='white' font-size='20' text-anchor='middle' dominant-baseline='middle'>Image " +
          hue +
          '</text></svg>'
      )
    );
  }
}

@NgModule({
  declarations: [AppComponent, LazyImageComponent],
  imports: [BrowserModule],
  bootstrap: [AppComponent],
})
export class AppModule {}
